content.content:
load_module /etc/nginx/modules/otel_ngx_module.so;
	opentelemetry_config /etc/ingress-controller/telemetry/opentelemetry.toml;
	log_format upstreaminfo '$remote_addr - $remote_user [$time_local] "$request" $status $body_bytes_sent "$http_referer" "$http_user_agent" otel_trace_id=$opentelemetry_trace_id otel_span_id=$opentelemetry_span_id';
			opentelemetry on;
			opentelemetry_propagate;
			opentelemetry_trust_incoming_spans on;
			opentelemetry off;
			opentelemetry off;
			opentelemetry on;
			opentelemetry_propagate;
			opentelemetry_trust_incoming_spans on;
			opentelemetry on;
			opentelemetry_propagate;
			opentelemetry_trust_incoming_spans on;
	## start server otel-alt.example.com
		server_name otel-alt.example.com ;
		location /otel-check/ {
			set $ingress_name   "otel-alt";
			set $service_name   "otel-echo";
			set $location_path  "/otel-check";
			opentelemetry on;
			opentelemetry_propagate;
			opentelemetry_trust_incoming_spans on;
			set $proxy_upstream_name "demo-otel-echo-5678";
		location = /otel-check {
			set $ingress_name   "otel-alt";
			set $service_name   "otel-echo";
			set $location_path  "/otel-check";
			opentelemetry on;
			opentelemetry_propagate;

